import { createContext, useContext } from "react";

import type { UseFormReturnOnChangeType } from "@/components/fsui/fsform/fsform";
import type { FieldDefinition, PKType, SchemaDefinition } from "fastschema";
import type * as z from "zod";

export interface ContentEditContextType<
  T extends z.ZodObject<Record<string, z.ZodType>> = z.ZodObject<
    Record<string, z.ZodType>
  >,
> {
  pkValue?: PKType;
  form: UseFormReturnOnChangeType<T>;
  schemaDef: SchemaDefinition;
  getField: (name: string) => FieldDefinition | undefined;
}

export const ContentEditContext = createContext<ContentEditContextType | null>(
  null,
);

export const useContentEditContext = <
  T extends ContentEditContextType["form"],
>() => {
  const context = useContext(ContentEditContext);
  if (!context) {
    throw new Error(
      "useContentEditContext must be used within ContentEditContext.Provider",
    );
  }
  return {
    ...context,
    form: context.form as T,
    isEditing: Boolean(context.pkValue),
  };
};

export const useContentEditForm = <
  T extends ContentEditContextType["form"],
>() => {
  return useContentEditContext<T>().form;
};

export const useSchemaDefinition = () => {
  return useContentEditContext().schemaDef;
};

export const useFieldDefinition = (name: string) => {
  return useContentEditContext().getField(name);
};

export const useContentEditPKValue = () => {
  const context = useContentEditContext();
  return context.pkValue as PKType | undefined;
};

import { Checkbox } from "@/components/ui/checkbox";
import { Field, FieldError, FieldLabel } from "@/components/ui/field";
import { Label } from "@/components/ui/label";
import { Switch } from "@/components/ui/switch";

import { FieldWrapper } from "./field-wrapper";

import type { BaseFieldProps } from "../types";

export type FieldBoolProps = BaseFieldProps;

type InlineLabelType = "none" | "left" | "right" | "boxed";

/**
 * Switch with inline label variants
 */
const SwitchVariant = ({
  fieldDef,
  fieldApi,
  inlineLabel,
  className,
}: FieldBoolProps & { inlineLabel: InlineLabelType }) => {
  const value = (fieldApi.state.value as boolean) ?? false;
  const isInvalid =
    fieldApi.state.meta.isTouched && !fieldApi.state.meta.isValid;

  // Left label
  if (inlineLabel === "left") {
    return (
      <Field
        className={className}
        data-invalid={isInvalid}
      >
        <div className="flex items-center space-x-2">
          <Label htmlFor={fieldDef.name}>{fieldDef.label}</Label>
          <Switch
            id={fieldDef.name}
            name={fieldDef.name}
            checked={value}
            onCheckedChange={(checked) => fieldApi.handleChange(checked)}
            onBlur={fieldApi.handleBlur}
          />
        </div>
        {isInvalid && <FieldError errors={fieldApi.state.meta.errors} />}
      </Field>
    );
  }

  // Right label
  if (inlineLabel === "right") {
    return (
      <Field
        className={className}
        data-invalid={isInvalid}
      >
        <div className="flex items-center space-x-2">
          <Switch
            id={fieldDef.name}
            name={fieldDef.name}
            checked={value}
            onCheckedChange={(checked) => fieldApi.handleChange(checked)}
            onBlur={fieldApi.handleBlur}
          />
          <Label htmlFor={fieldDef.name}>{fieldDef.label}</Label>
        </div>
        {isInvalid && <FieldError errors={fieldApi.state.meta.errors} />}
      </Field>
    );
  }

  // Boxed
  if (inlineLabel === "boxed") {
    return (
      <Field
        className={className}
        data-invalid={isInvalid}
      >
        <div className="flex flex-row items-center justify-between rounded-lg border px-3 shadow-sm">
          <Switch
            id={fieldDef.name}
            name={fieldDef.name}
            checked={value}
            onCheckedChange={(checked) => fieldApi.handleChange(checked)}
            onBlur={fieldApi.handleBlur}
          />
        </div>
        {isInvalid && <FieldError errors={fieldApi.state.meta.errors} />}
      </Field>
    );
  }

  // None - just switch, wrapper handles label
  return (
    <FieldWrapper
      fieldDef={fieldDef}
      fieldApi={fieldApi}
    >
      <Switch
        id={fieldDef.name}
        name={fieldDef.name}
        checked={value}
        onCheckedChange={(checked) => fieldApi.handleChange(checked)}
        onBlur={fieldApi.handleBlur}
        aria-invalid={isInvalid}
      />
    </FieldWrapper>
  );
};

/**
 * Default checkbox variant
 */
const CheckboxVariant = ({ fieldDef, fieldApi, className }: FieldBoolProps) => {
  const isInvalid =
    fieldApi.state.meta.isTouched && !fieldApi.state.meta.isValid;
  const value = (fieldApi.state.value as boolean) ?? false;

  return (
    <Field
      className={className}
      data-invalid={isInvalid}
      orientation="horizontal"
    >
      <Checkbox
        id={fieldDef.name}
        checked={value}
        onCheckedChange={(checked) => fieldApi.handleChange(checked === true)}
        onBlur={fieldApi.handleBlur}
        aria-invalid={isInvalid}
      />
      <FieldLabel
        htmlFor={fieldDef.name}
        className="cursor-pointer"
      >
        {fieldDef.label}
      </FieldLabel>
      {isInvalid && <FieldError errors={fieldApi.state.meta.errors} />}
    </Field>
  );
};

/**
 * FieldBool - Boolean field with switch variants
 *
 * Variants (via renderer.class or renderer.settings.inline_label):
 * - checkbox (default): Checkbox with label
 * - switch: Basic switch
 * - switch with inline_label: left, right, or boxed
 */
export const FieldBool = ({
  fieldDef,
  fieldApi,
  renderer,
  rendererOptions,
  className,
}: FieldBoolProps) => {
  const inlineLabel = rendererOptions?.inline_label as
    | InlineLabelType
    | undefined;

  // Switch variants
  if (renderer === "switch") {
    return (
      <SwitchVariant
        fieldDef={fieldDef}
        fieldApi={fieldApi}
        inlineLabel={inlineLabel ?? "none"}
        className={className}
      />
    );
  }

  // Check for switch_* renderer classes (legacy compatibility)
  if (renderer === "switch_left") {
    return (
      <SwitchVariant
        fieldDef={fieldDef}
        fieldApi={fieldApi}
        inlineLabel="left"
        className={className}
      />
    );
  }
  if (renderer === "switch_right") {
    return (
      <SwitchVariant
        fieldDef={fieldDef}
        fieldApi={fieldApi}
        inlineLabel="right"
        className={className}
      />
    );
  }
  if (renderer === "switch_boxed") {
    return (
      <SwitchVariant
        fieldDef={fieldDef}
        fieldApi={fieldApi}
        inlineLabel="boxed"
        className={className}
      />
    );
  }

  // Default: Checkbox
  return (
    <CheckboxVariant
      fieldDef={fieldDef}
      fieldApi={fieldApi}
      className={className}
    />
  );
};

import { useEffect, useState } from "react";
import { ChromePicker } from "react-color";

import { Input } from "@/components/ui/input";
import {
  Popover,
  PopoverContent,
  PopoverTrigger,
} from "@/components/ui/popover";

import { FieldWrapper } from "./field-wrapper";

import type { BaseFieldProps } from "../types";

export type FieldColorPickerProps = BaseFieldProps;

/**
 * Convert decimal alpha to hex
 */
function decimalToHex(alpha: number): string {
  const aHex = Math.round(255 * alpha).toString(16);
  if (alpha === 0) {
    return "00";
  }
  return aHex.length < 2 ? `0${aHex}` : aHex;
}

/**
 * FieldColorPicker - Color picker field with popover
 */
export const FieldColorPicker = ({
  fieldDef,
  fieldApi,
}: FieldColorPickerProps) => {
  const value = (fieldApi.state.value as string) ?? "#FFFFFF";
  const [selectedColor, setSelectedColor] = useState<string>(value);

  useEffect(() => {
    if (selectedColor !== value) {
      fieldApi.handleChange(selectedColor);
    }
  }, [selectedColor, fieldApi, value]);

  return (
    <FieldWrapper
      fieldDef={fieldDef}
      fieldApi={fieldApi}
    >
      <div className="flex items-center gap-2">
        <Input
          id={fieldDef.name}
          value={selectedColor}
          onChange={(e) => setSelectedColor(e.target.value)}
          onBlur={fieldApi.handleBlur}
        />
        <Popover>
          <PopoverTrigger asChild>
            <div
              className="h-9 w-9 shrink-0 cursor-pointer rounded border-2"
              style={{ backgroundColor: selectedColor }}
            />
          </PopoverTrigger>
          <PopoverContent className="w-[230px] p-0">
            <ChromePicker
              className="color-picker-chrome"
              color={selectedColor}
              onChange={(color) => {
                const hexCode = `${color.hex}${decimalToHex(color.rgb.a ?? 1)}`;
                setSelectedColor(hexCode);
              }}
            />
          </PopoverContent>
        </Popover>
      </div>
    </FieldWrapper>
  );
};

import { useFastSchema } from "fastschema/react";

import { Editor } from "@/components/fsui/fseditor";

import { FieldWrapper } from "./field-wrapper";

import type { BaseFieldProps } from "../types";

export type FieldEditorProps = BaseFieldProps;

/**
 * FieldEditor - Rich text editor field
 */
export const FieldEditor = ({ fieldDef, fieldApi }: FieldEditorProps) => {
  const { fastschema } = useFastSchema();
  const value = (fieldApi.state.value as string) ?? "";

  // Persist inline images through the real file API instead of the editor's
  // placeholder, so pasted/dropped images survive a page reload.
  const uploader = async (file: File): Promise<string> => {
    const result = await fastschema.file().upload([file]);
    const url = result.success[0]?.url;
    if (!url) {
      throw new Error("File upload failed");
    }
    return url;
  };

  return (
    <FieldWrapper
      fieldDef={fieldDef}
      fieldApi={fieldApi}
    >
      <Editor
        value={value}
        onChange={(content: string) => fieldApi.handleChange(content)}
        uploader={uploader}
      />
    </FieldWrapper>
  );
};

import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from "@/components/ui/select";

import { FieldWrapper } from "./field-wrapper";

import type { BaseFieldProps } from "../types";

export type FieldEnumProps = BaseFieldProps;

/**
 * FieldEnum - Enum field using Select component
 */
export const FieldEnum = ({ fieldDef, fieldApi }: FieldEnumProps) => {
  const isInvalid =
    fieldApi.state.meta.isTouched && !fieldApi.state.meta.isValid;
  const value = (fieldApi.state.value as string) ?? "";
  const enums = fieldDef.enums ?? [];

  return (
    <FieldWrapper
      fieldDef={fieldDef}
      fieldApi={fieldApi}
    >
      <Select
        value={value}
        onValueChange={(val) => fieldApi.handleChange(val)}
        name={fieldDef.name}
      >
        <SelectTrigger
          id={fieldDef.name}
          aria-invalid={isInvalid}
          className="w-full"
        >
          <SelectValue
            placeholder={`Select ${fieldDef.label.toLowerCase()}...`}
          />
        </SelectTrigger>
        <SelectContent>
          {enums.map((enumItem) => (
            <SelectItem
              key={enumItem.value}
              value={enumItem.value}
            >
              {enumItem.label}
            </SelectItem>
          ))}
        </SelectContent>
      </Select>
    </FieldWrapper>
  );
};

import {
  getFileTypeLabel,
  type FileTypeFilter,
  type FsFile,
  type PKType,
} from "fastschema";
import { useFastSchema, useContentList } from "fastschema/react";
import { ImageIcon, Upload } from "lucide-react";
import { useCallback, useState, useMemo } from "react";
import { toast } from "sonner";

import { Button } from "@/components/ui/button";
import { FieldLabel } from "@/components/ui/field";
import { cn } from "@/lib/utils";
import { Loading } from "@/components/fsui/fscommon";
import { FilePickerModal } from "@/components/fsui/fsmedia";

import { useContentEditContext, useContentEditPKValue } from "../../context";
import { FieldWrapper } from "../field-wrapper";

import { FilePreview } from "./preview";

import type { BaseFieldProps } from "../../types";

const PREVIEW_LIMIT = 5;

export const FieldFile = ({
  fieldDef,
  fieldApi,
  rendererOptions,
}: BaseFieldProps) => {
  const { fastschema } = useFastSchema();
  const { schemaDef } = useContentEditContext();
  const [modalOpen, setModalOpen] = useState(false);
  const [isRemoving, setIsRemoving] = useState(false);
  const pkValue = useContentEditPKValue();
  const isEditMode = Boolean(pkValue);
  const isMultiple = fieldDef.multiple ?? false;
  const allowedFileType = (rendererOptions?.type as FileTypeFilter) ?? "all";
  // "dropzone" renders a large click-to-upload area instead of the default
  // button (opt-in via rendererOptions.variant); upload logic is unchanged.
  const variant =
    (rendererOptions?.variant as "button" | "dropzone" | undefined) ?? "button";
  const backRef = fastschema.getBackRefField(schemaDef.name, fieldDef);
  const attachedFilesQuery = useContentList<FsFile>({
    schemaName: "file",
    limit: PREVIEW_LIMIT,
    filter: backRef?.name ? { [backRef.name]: { $eq: pkValue } } : undefined,
    dummy: !isEditMode || !backRef,
  });

  const getFormFiles = useCallback((): FsFile[] => {
    const value = fieldApi.state.value as FsFile | FsFile[] | null;
    return value ? (Array.isArray(value) ? value : [value]) : [];
  }, [fieldApi.state.value]);

  const selectedFiles = useMemo(() => {
    return isEditMode && attachedFilesQuery.result?.items
      ? attachedFilesQuery.result.items
      : getFormFiles();
  }, [isEditMode, attachedFilesQuery.result?.items, getFormFiles]);

  const displayFiles = useMemo(() => {
    return selectedFiles.slice(0, PREVIEW_LIMIT);
  }, [selectedFiles]);

  const totalFiles = isEditMode
    ? (attachedFilesQuery.result?.total ?? 0)
    : selectedFiles.length;

  const handleFileSelect = useCallback(
    (file: FsFile | FsFile[]) => {
      if (isMultiple) {
        const files = Array.isArray(file) ? file : [file];
        const merged = [...getFormFiles()];
        for (const f of files) {
          if (!merged.some((m) => m.id === f.id)) {
            merged.push(f);
          }
        }
        fieldApi.handleChange(merged);
      } else {
        const singleFile = Array.isArray(file) ? file[0] : file;
        fieldApi.handleChange(singleFile);
      }
    },
    [isMultiple, getFormFiles, fieldApi],
  );

  const handleRemove = useCallback(
    async (file: FsFile) => {
      if (isEditMode) {
        setIsRemoving(true);
        try {
          const schema = fastschema.schema(schemaDef.name);
          await schema?.update(pkValue as PKType, {
            [fieldDef.name]: {
              $clear: [{ id: file.id }],
            },
          });
          toast.success("File detached successfully");
          attachedFilesQuery.reFetch();
        } catch (error_) {
          toast.error(`Failed to detach file: ${(error_ as Error).message}`);
        } finally {
          setIsRemoving(false);
        }
      } else {
        if (isMultiple) {
          const current = getFormFiles();
          const filtered = current.filter((f) => f.id !== file.id);
          fieldApi.handleChange(filtered.length > 0 ? filtered : null);
        } else {
          fieldApi.handleChange(null);
        }
      }
    },
    [
      isEditMode,
      isMultiple,
      getFormFiles,
      fieldApi,
      fastschema,
      schemaDef.name,
      pkValue,
      fieldDef.name,
      attachedFilesQuery,
    ],
  );

  const isLoadingFiles = isEditMode && attachedFilesQuery.isLoading;

  return (
    <FieldWrapper
      fieldDef={fieldDef}
      fieldApi={fieldApi}
      hideLabel
    >
      <FieldLabel asChild>
        <span className="flex items-center gap-1">
          {fieldDef.label}
          {!fieldDef.optional && <span className="text-destructive">*</span>}
          {isMultiple && totalFiles > 0 && (
            <span className="text-muted-foreground text-xs font-normal">
              ({totalFiles} file{totalFiles === 1 ? "" : "s"})
            </span>
          )}
          <span className="text-muted-foreground text-xs font-normal">
            {[
              isMultiple ? "Multiple files allowed" : "Single file only",
              allowedFileType === "all"
                ? null
                : getFileTypeLabel(allowedFileType),
            ]
              .filter(Boolean)
              .join(" - ")}
          </span>
        </span>
      </FieldLabel>
      <div className="flex flex-col gap-3">
        {!displayFiles?.length &&
          (variant === "dropzone" ? (
            <button
              type="button"
              onClick={() => setModalOpen(true)}
              disabled={isLoadingFiles}
              className="border-border bg-muted/20 hover:border-primary hover:bg-primary/5 group flex h-48 w-full cursor-pointer flex-col items-center justify-center rounded-xl border-2 border-dashed transition-all disabled:cursor-not-allowed disabled:opacity-60"
            >
              <span className="bg-primary/10 mb-3 flex size-12 items-center justify-center rounded-full transition-transform group-hover:scale-110">
                <Upload className="text-primary size-5" />
              </span>
              <span className="text-sm font-medium">
                Click to upload {isMultiple ? "files" : "a file"}
              </span>
              {allowedFileType !== "all" && (
                <span className="text-muted-foreground mt-1 text-xs">
                  {getFileTypeLabel(allowedFileType)}
                </span>
              )}
            </button>
          ) : (
            <Button
              type="button"
              variant="outline"
              onClick={() => setModalOpen(true)}
              className="w-fit"
              disabled={isLoadingFiles}
              size="sm"
            >
              <ImageIcon className="h-4 w-4" />
              {totalFiles > 0 ? "Change" : "Select"}{" "}
              {isMultiple ? "Files" : "File"}
            </Button>
          ))}

        {isLoadingFiles ? (
          <Loading />
        ) : (
          displayFiles.length > 0 && (
            <div
              className={cn(
                "grid flex-wrap items-center gap-3",
                displayFiles.length === 1
                  ? "grid-cols-1"
                  : displayFiles.length === 2
                    ? "grid-cols-2"
                    : "grid-cols-3",
              )}
            >
              {displayFiles.map((file) => (
                <FilePreview
                  key={file.id}
                  file={file}
                  onRemove={handleRemove}
                  isRemoving={isRemoving}
                  trigger={
                    !isMultiple && (
                      <div className="absolute inset-0 flex items-center justify-center">
                        <Button
                          type="button"
                          variant="secondary"
                          size="sm"
                          onClick={() => setModalOpen(true)}
                        >
                          Change
                        </Button>
                      </div>
                    )
                  }
                />
              ))}
              {isMultiple && (
                <button
                  type="button"
                  className="bg-muted text-muted-foreground ring-primary/90 flex h-24 w-24 items-center justify-center rounded text-sm font-medium transition-shadow hover:ring-3"
                  onClick={() => setModalOpen(true)}
                >
                  Library
                </button>
              )}
            </div>
          )
        )}

        {modalOpen && (
          <FilePickerModal
            open={modalOpen}
            onOpenChange={setModalOpen}
            onFileSelect={isEditMode ? undefined : handleFileSelect}
            selectionMode={isMultiple ? "multiple" : "single"}
            allowedFileType={allowedFileType}
            // Edit mode props
            schemaName={isEditMode ? schemaDef.name : undefined}
            pkValue={isEditMode ? pkValue : undefined}
            fieldName={isEditMode ? fieldDef.name : undefined}
            backRefFieldName={isEditMode ? backRef?.name : undefined}
            onAttachDetachComplete={
              isEditMode ? () => attachedFilesQuery.reFetch() : undefined
            }
          />
        )}
      </div>
    </FieldWrapper>
  );
};

import { FileIcon, XIcon } from "lucide-react";

import type { FsFile } from "fastschema";
import type { ReactNode } from "react";

export const FilePreview = ({
  file,
  isRemoving,
  trigger,
  onRemove,
}: {
  file: FsFile;
  isRemoving?: boolean;
  trigger?: ReactNode;
  onRemove: (file: FsFile) => void;
}) => {
  const isImage = file.type?.startsWith("image/");

  return (
    <div className="group ring-primary/90 relative aspect-square max-w-32 overflow-hidden rounded shadow-xl transition-shadow hover:ring-3">
      {isImage && file.url ? (
        <img
          src={file.url}
          alt={file.name}
          className="h-full w-full object-cover"
        />
      ) : (
        <div className="bg-muted flex h-full w-full items-center justify-center">
          <FileIcon className="text-muted-foreground h-8 w-8" />
        </div>
      )}
      <button
        type="button"
        onClick={() => onRemove(file)}
        disabled={isRemoving}
        className="bg-secondary/90 text-primary group-hover:bg-secondary group-hover:text-destructive absolute top-1 right-1 z-10 flex h-5 w-5 items-center justify-center rounded-full p-1 shadow-md transition-opacity disabled:opacity-50"
        title="Remove"
      >
        <XIcon className="size-3" />
      </button>
      <div className="absolute right-0 bottom-0 left-0 truncate bg-black/50 px-1.5 py-0.5 text-xs text-white">
        {file.name}
      </div>
      {trigger}
    </div>
  );
};

import { Input } from "@/components/ui/input";

import { FieldWrapper } from "./field-wrapper";

import type { BaseFieldProps } from "../types";

export type FieldInputProps = BaseFieldProps;

/**
 * FieldInput - Default text input field
 */
export const FieldInput = ({ fieldDef, fieldApi }: FieldInputProps) => {
  const isInvalid =
    fieldApi.state.meta.isTouched && !fieldApi.state.meta.isValid;
  const value = (fieldApi.state.value as string) ?? "";

  return (
    <FieldWrapper
      fieldDef={fieldDef}
      fieldApi={fieldApi}
      description={
        fieldDef.type === "uuid" ? "UUID format required" : undefined
      }
    >
      <Input
        id={fieldDef.name}
        name={fieldDef.name}
        type="text"
        value={value}
        onBlur={fieldApi.handleBlur}
        onChange={(e) => fieldApi.handleChange(e.target.value)}
        aria-invalid={isInvalid}
        placeholder={`Enter ${fieldDef.label.toLowerCase()}...`}
        maxLength={fieldDef.size}
        autoComplete="on"
      />
    </FieldWrapper>
  );
};

import { useCallback, useState } from "react";

import { Textarea } from "@/components/ui/textarea";

import { FieldWrapper } from "./field-wrapper";

import type { BaseFieldProps } from "../types";

export type FieldJsonProps = BaseFieldProps;

/**
 * FieldJson - JSON field with validation
 */
export const FieldJson = ({ fieldDef, fieldApi }: FieldJsonProps) => {
  const isInvalid =
    fieldApi.state.meta.isTouched && !fieldApi.state.meta.isValid;

  // Store raw text for display
  const [textValue, setTextValue] = useState<string>(() => {
    const val = fieldApi.state.value;
    if (val === null || val === undefined) return "";
    if (typeof val === "string") return val;
    return JSON.stringify(val, null, 2);
  });

  const [jsonError, setJsonError] = useState<string | null>(null);

  const handleChange = useCallback(
    (e: React.ChangeEvent<HTMLTextAreaElement>) => {
      const val = e.target.value;
      setTextValue(val);

      if (val.trim() === "") {
        setJsonError(null);
        fieldApi.handleChange(null);
        return;
      }

      try {
        const parsed = JSON.parse(val);
        setJsonError(null);
        fieldApi.handleChange(parsed);
      } catch {
        setJsonError("Invalid JSON format");
        // Still update field to trigger validation
        fieldApi.handleChange(val);
      }
    },
    [fieldApi],
  );

  return (
    <FieldWrapper
      fieldDef={fieldDef}
      fieldApi={fieldApi}
      description={jsonError ?? "Enter valid JSON"}
    >
      <Textarea
        id={fieldDef.name}
        name={fieldDef.name}
        value={textValue}
        onBlur={fieldApi.handleBlur}
        onChange={handleChange}
        aria-invalid={isInvalid || !!jsonError}
        placeholder='{"key": "value"}'
        rows={6}
        className="font-mono text-sm"
      />
    </FieldWrapper>
  );
};

import { Input } from "@/components/ui/input";

import { FieldWrapper } from "./field-wrapper";

import type { BaseFieldProps } from "../types";
import type { FieldType } from "fastschema";

export type FieldNumberProps = BaseFieldProps;

/**
 * Get constraints based on numeric type
 */
function getNumberConstraints(type: FieldType): {
  min?: number;
  max?: number;
  step: number | "any";
} {
  switch (type) {
    case "int8": {
      return { min: -128, max: 127, step: 1 };
    }
    case "int16": {
      return { min: -32768, max: 32767, step: 1 };
    }
    case "int32": {
      return { min: -2147483648, max: 2147483647, step: 1 };
    }
    case "uint8": {
      return { min: 0, max: 255, step: 1 };
    }
    case "uint16": {
      return { min: 0, max: 65535, step: 1 };
    }
    case "uint32": {
      return { min: 0, max: 4294967295, step: 1 };
    }
    case "uint":
    case "uint64": {
      return { min: 0, step: 1 };
    }
    case "int":
    case "int64": {
      return { step: 1 };
    }
    case "float32":
    case "float64": {
      return { step: "any" };
    }
    default: {
      return { step: 1 };
    }
  }
}

/**
 * FieldNumber - Numeric field with type-specific constraints
 */
export const FieldNumber = ({ fieldDef, fieldApi }: FieldNumberProps) => {
  const isInvalid =
    fieldApi.state.meta.isTouched && !fieldApi.state.meta.isValid;
  const value = fieldApi.state.value as number | undefined;
  const constraints = getNumberConstraints(fieldDef.type);

  const handleChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const val = e.target.value;
    if (val === "") {
      fieldApi.handleChange(undefined);
      return;
    }

    const numVal =
      fieldDef.type === "float32" || fieldDef.type === "float64"
        ? Number.parseFloat(val)
        : Number.parseInt(val, 10);

    if (!Number.isNaN(numVal)) {
      fieldApi.handleChange(numVal);
    }
  };

  return (
    <FieldWrapper
      fieldDef={fieldDef}
      fieldApi={fieldApi}
    >
      <Input
        id={fieldDef.name}
        name={fieldDef.name}
        type="number"
        value={value ?? ""}
        onBlur={fieldApi.handleBlur}
        onChange={handleChange}
        aria-invalid={isInvalid}
        placeholder={`Enter ${fieldDef.label.toLowerCase()}...`}
        min={constraints.min}
        max={constraints.max}
        step={constraints.step}
      />
    </FieldWrapper>
  );
};

