export type FieldRelationProps = BaseFieldProps & {
  fieldDef: RelationFieldDefinition;
};

const fieldLabelClassNames =
  "group/field-label peer/field-label flex w-fit items-center gap-1 text-sm leading-snug font-medium select-none";
const inputGroupClassNames =
  "hover:border-ring hover:ring-ring/50 aria-invalid:ring-destructive/20 dark:aria-invalid:ring-destructive/40 aria-invalid:border-destructive h-auto items-start hover:ring-3";
const attachedBadgeClassNames =
  "border-input flex w-full min-w-0 flex-1 flex-wrap gap-1 bg-transparent p-2 text-base md:text-sm dark:bg-transparent";

export const FieldRelation = ({ fieldDef, fieldApi }: FieldRelationProps) => {
  const { fastschema } = useFastSchema();
  const { schemaDef: schemaDefinition } = useContentEditContext();
  const pkValue = useContentEditPKValue();
  const isMany = isRelationManyValues(fieldDef.relation);
  const isEditMode = Boolean(pkValue);
  const isInvalid =
    fieldApi.state.meta.isTouched && !fieldApi.state.meta.isValid;
  const backRef = fastschema.getBackRefField(schemaDefinition.name, fieldDef);
  const { primaryCol, labelCol } = fastschema.relationInfo(fieldDef);
  const [selectedEntities, setSelectedEntities] = useState<Entity[]>([]);
  const relationPickerRef = useRef<RelationPickerRef>(null);
  const query = useContentList({
    limit: 5,
    page: 1,
    schemaName: fieldDef.relation.schema,
    filter: { [backRef?.name as string]: { $eq: pkValue } },
    dummy: !isEditMode,
  });

  const handleSelectionChange = useCallback(
    (entities: Entity[]) => {
      // Edit mode uses API, not form state
      if (isEditMode) return;
      setSelectedEntities(entities);
      fieldApi.handleChange(isMany ? entities : entities[0]);
    },
    [isEditMode, fieldApi, isMany],
  );

  const handleRemoveItem = useCallback(
    async (entity: Entity) => {
      if (isEditMode) {
        await relationPickerRef.current?.updateRelation("$clear", [entity]);
        query.reFetch();
        return;
      }

      const newEntities = selectedEntities.filter(
        (e) => e[primaryCol] !== entity[primaryCol],
      );
      fieldApi.handleChange(isMany ? newEntities : newEntities[0]);
      setSelectedEntities((prev) =>
        prev.filter((e) => e[primaryCol] !== entity[primaryCol]),
      );
    },
    [isEditMode, selectedEntities, fieldApi, primaryCol, isMany, query],
  );

  if (!backRef) {
    return (
      <AlertError
        error={
          new Error(
            `No back-reference relation found for field "${fieldDef.name}"`,
          )
        }
      />
    );
  }

  const displayItems = isEditMode ? (query?.result?.items ?? []) : [];
  const totalConnected = isEditMode
    ? query?.result?.total || 0
    : selectedEntities.length;

  return (
    <FieldWrapper
      fieldDef={fieldDef}
      fieldApi={fieldApi}
      hideLabel
    >
      <div className={fieldLabelClassNames}>
        {fieldDef.label}
        {!fieldDef.optional && <span className="text-destructive">*</span>}
        {totalConnected > 0 && (
          <span className="text-muted-foreground text-xs font-normal">
            ({totalConnected} item
            {totalConnected === 1 ? "" : "s"})
          </span>
        )}
      </div>
      <InputGroup
        aria-invalid={isInvalid}
        className={inputGroupClassNames}
      >
        <div className={attachedBadgeClassNames}>
          {isEditMode
            ? displayItems.map((item) => {
                const label = item[labelCol] ?? item[primaryCol] ?? "";
                const key =
                  item[primaryCol] ??
                  item[labelCol || ""] ??
                  Math.random().toString();

                return (
                  <Badge
                    key={String(key)}
                    variant="secondary"
                    className="max-w-full gap-1 overflow-hidden text-ellipsis whitespace-nowrap"
                  >
                    {String(label)}
                    <button
                      type="button"
                      className="hover:bg-muted-foreground/20 -mr-1 rounded-full p-0.5"
                      onClick={() => handleRemoveItem(item)}
                      aria-label={`Detach ${label}`}
                    >
                      <XIcon className="size-3" />
                    </button>
                  </Badge>
                );
              })
            : selectedEntities.map((e) => {
                const label = e[labelCol];
                return (
                  <Badge
                    key={e[primaryCol] as PKType}
                    variant="secondary"
                    className="max-w-full gap-1 overflow-hidden text-ellipsis whitespace-nowrap"
                  >
                    {String(label)}
                    <button
                      type="button"
                      className="hover:bg-muted-foreground/20 -mr-1 rounded-full p-0.5"
                      onClick={() => handleRemoveItem(e)}
                      aria-label={`Remove ${label}`}
                    >
                      <XIcon className="size-3" />
                    </button>
                  </Badge>
                );
              })}
        </div>
        <InputGroupAddon
          align="inline-end"
          className="pr-1.5"
        >
          {isEditMode && pkValue ? (
            // Edit mode: manage mode picker (uses API)
            <RelationPicker
              ref={relationPickerRef}
              schemaName={schemaDefinition.name}
              pkValue={pkValue}
              relationField={fieldDef}
              onClose={() => query.reFetch()}
              availableRecordsFilter={{ [backRef.name]: { $neq: pkValue } }}
              connectedRecordsFilter={{ [backRef.name]: { $eq: pkValue } }}
              trigger={
                <InputGroupButton
                  aria-label="Manage relations"
                  title="Manage relations"
                  size="icon-xs"
                >
                  <SettingsIcon />
                </InputGroupButton>
              }
            />
          ) : (
            // Create mode: select mode picker (uses form state)
            <RelationPicker
              schemaName={fieldDef.relation.schema}
              relationField={fieldDef}
              value={selectedEntities}
              onSelectionChange={handleSelectionChange}
              multiple={isMany}
              trigger={
                <InputGroupButton
                  aria-label="Select relations"
                  title="Select relations"
                  size="icon-xs"
                >
                  <SettingsIcon />
                </InputGroupButton>
              }
            />
          )}
        </InputGroupAddon>
      </InputGroup>
    </FieldWrapper>
  );
};

