import { format } from "date-fns";
import { CalendarIcon, ChevronDownIcon, XIcon } from "lucide-react";
import { useState } from "react";

import { Button } from "@/components/ui/button";
import { Calendar } from "@/components/ui/calendar";
import { Input } from "@/components/ui/input";
import {
  Popover,
  PopoverContent,
  PopoverTrigger,
} from "@/components/ui/popover";
import { cn } from "@/lib/utils";

import { FieldWrapper } from "./field-wrapper";

import type { BaseFieldProps } from "../types";

export type FieldTimeProps = BaseFieldProps;

type TimeFormat = "datetime" | "date_only" | "time_only";

/**
 * Parse a date value to a Date object
 */
function parseDate(value: unknown): Date | undefined {
  if (!value) return undefined;
  if (value instanceof Date) return value;
  if (typeof value === "string") {
    const date = new Date(value);
    return Number.isNaN(date.getTime()) ? undefined : date;
  }
  return undefined;
}

/**
 * Format time for the time input (HH:mm)
 */
function formatTimeInput(date: Date | undefined): string {
  if (!date) return "";
  const hours = String(date.getHours()).padStart(2, "0");
  const minutes = String(date.getMinutes()).padStart(2, "0");
  return `${hours}:${minutes}`;
}

/**
 * FieldTime - DateTime field with shadcn date-picker
 *
 * Variants (via rendererOptions.format):
 * - datetime (default): Show both date picker and time input
 * - date_only: Show only date picker
 * - time_only: Show only time input
 */
export const FieldTime = ({
  fieldDef,
  fieldApi,
  rendererOptions,
}: FieldTimeProps) => {
  const [open, setOpen] = useState(false);
  const isInvalid =
    fieldApi.state.meta.isTouched && !fieldApi.state.meta.isValid;
  const value = parseDate(fieldApi.state.value);

  // Get format from rendererOptions, default to datetime
  const timeFormat = (rendererOptions?.format as TimeFormat) ?? "datetime";
  const showDate = timeFormat === "datetime" || timeFormat === "date_only";
  const showTime = timeFormat === "datetime" || timeFormat === "time_only";

  const handleDateSelect = (date: Date | undefined) => {
    if (!date) {
      fieldApi.handleChange(null);
      setOpen(false);
      return;
    }

    // Preserve time if we have an existing value
    if (value) {
      date.setHours(value.getHours());
      date.setMinutes(value.getMinutes());
      date.setSeconds(value.getSeconds());
    }

    fieldApi.handleChange(date.toISOString());
    setOpen(false);
  };

  const handleTimeChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const timeStr = e.target.value;
    if (!timeStr) return;

    const [hours, minutes] = timeStr.split(":").map(Number);
    const date = value ? new Date(value) : new Date();
    date.setHours(hours);
    date.setMinutes(minutes);
    date.setSeconds(0);

    fieldApi.handleChange(date.toISOString());
  };

  const handleClear = () => {
    fieldApi.handleChange(null);
  };

  return (
    <FieldWrapper
      fieldDef={fieldDef}
      fieldApi={fieldApi}
    >
      <div className="flex items-center gap-2">
        {/* Date Picker */}
        {showDate && (
          <Popover
            open={open}
            onOpenChange={setOpen}
          >
            <PopoverTrigger asChild>
              <Button
                variant="outline"
                id={fieldApi.name}
                className={cn(
                  "flex-1 justify-between font-normal",
                  !value && "text-muted-foreground",
                )}
                aria-invalid={isInvalid}
              >
                <span className="flex items-center">
                  <CalendarIcon className="mr-2 h-4 w-4" />
                  {value ? format(value, "yyyy-MM-dd") : "Select date"}
                </span>
                <ChevronDownIcon className="h-4 w-4 opacity-50" />
              </Button>
            </PopoverTrigger>
            <PopoverContent
              className="w-auto overflow-hidden p-0"
              align="start"
            >
              <Calendar
                mode="single"
                selected={value}
                onSelect={handleDateSelect}
                captionLayout="dropdown"
                autoFocus
              />
            </PopoverContent>
          </Popover>
        )}

        {/* Time Input */}
        {showTime && (
          <Input
            type="time"
            id={showTime && !showDate ? fieldDef.name : undefined}
            value={formatTimeInput(value)}
            onChange={handleTimeChange}
            onBlur={fieldApi.handleBlur}
            className={cn(
              "bg-background appearance-none [&::-webkit-calendar-picker-indicator]:hidden [&::-webkit-calendar-picker-indicator]:appearance-none",
              showDate ? "w-[150px]" : "flex-1",
            )}
            aria-invalid={isInvalid}
          />
        )}

        {/* Clear Button */}
        {value && (
          <Button
            type="button"
            variant="ghost"
            size="icon"
            onClick={handleClear}
            className="h-8 w-8 shrink-0"
            title="Clear"
          >
            <XIcon className="h-4 w-4" />
          </Button>
        )}
      </div>
    </FieldWrapper>
  );
};

