import { FieldPassword } from "./field-password";
import { FieldRelation } from "./field-relation";
import { FieldTextarea } from "./field-textarea";
import { FieldTime } from "./field-time";
import { fieldRegistry } from "./registry";

import type { FieldApiOnChangeType } from "../../fsform/fsform";
import type {
  ControlledFieldProps,
  FieldProps,
  RendererOptions,
} from "../types";
import type { FieldDefinition, RelationFieldDefinition } from "fastschema";

export interface ContentFieldProps {
  fieldName: string;
  renderer?: string;
  rendererOptions?: RendererOptions;
}

/**
 * Create a minimal mock fieldApi for controlled mode
 * This allows FieldRenderer to work with both fieldApi and controlled props
 */
function createControlledFieldApi(props: ControlledFieldProps) {
  const noop = () => undefined;
  return {
    state: {
      value: props.value,
      meta: {
        isTouched: false,
        isValid: true,
        errors: [],
      },
    },
    handleChange: props.onChange,
    handleBlur: props.onBlur ?? noop,
  } as unknown as FieldApiOnChangeType;
}

/**
 * Check if props are in controlled mode
 */
function isControlledProps(props: FieldProps): props is ControlledFieldProps {
  return "value" in props && "onChange" in props && !("fieldApi" in props);
}

export const FieldRenderer = (props: FieldProps) => {
  const { fieldDef, renderer, rendererOptions } = props;
  const fieldApi = isControlledProps(props)
    ? createControlledFieldApi(props)
    : props.fieldApi;

  const CustomRenderer = fieldRegistry.getRenderer(fieldDef, renderer);
  if (CustomRenderer) {
    return (
      <CustomRenderer
        fieldDef={fieldDef}
        fieldApi={fieldApi}
        renderer={renderer}
        rendererOptions={rendererOptions}
      />
    );
  }

  switch (fieldDef.type) {
    case "string":
    case "text":
    case "uuid":
    case "bytes": {
      // Determine which string variant to use based on renderer
      if (renderer === "color_picker") {
        return (
          <FieldColorPicker
            fieldDef={fieldDef}
            fieldApi={fieldApi}
            renderer={renderer}
            rendererOptions={rendererOptions}
          />
        );
      }
      if (renderer === "editor") {
        return (
          <FieldEditor
            fieldDef={fieldDef}
            fieldApi={fieldApi}
            renderer={renderer}
            rendererOptions={rendererOptions}
          />
        );
      }
      if (renderer === "textarea" || fieldDef.type === "text") {
        return (
          <FieldTextarea
            fieldDef={fieldDef}
            fieldApi={fieldApi}
            renderer={renderer}
            rendererOptions={rendererOptions}
          />
        );
      }
      if (renderer === "password") {
        return (
          <FieldPassword
            fieldDef={fieldDef}
            fieldApi={fieldApi}
            renderer={renderer}
            rendererOptions={rendererOptions}
          />
        );
      }
      // Default to input
      return (
        <FieldInput
          fieldDef={fieldDef}
          fieldApi={fieldApi}
          renderer={renderer}
          rendererOptions={rendererOptions}
        />
      );
    }

    case "int":
    case "int8":
    case "int16":
    case "int32":
    case "int64":
    case "uint":
    case "uint8":
    case "uint16":
    case "uint32":
    case "uint64":
    case "float32":
    case "float64": {
      return (
        <FieldNumber
          fieldDef={fieldDef}
          fieldApi={fieldApi}
          renderer={renderer}
          rendererOptions={rendererOptions}
        />
      );
    }

    case "bool": {
      return (
        <FieldBool
          fieldDef={fieldDef}
          fieldApi={fieldApi}
          renderer={renderer}
          rendererOptions={rendererOptions}
        />
      );
    }

    case "enum": {
      return (
        <FieldEnum
          fieldDef={fieldDef}
          fieldApi={fieldApi}
          renderer={renderer}
          rendererOptions={rendererOptions}
        />
      );
    }

    case "time": {
      return (
        <FieldTime
          fieldDef={fieldDef}
          fieldApi={fieldApi}
          renderer={renderer}
          rendererOptions={rendererOptions}
        />
      );
    }

    case "json": {
      return (
        <FieldJson
          fieldDef={fieldDef}
          fieldApi={fieldApi}
          renderer={renderer}
          rendererOptions={rendererOptions}
        />
      );
    }

    case "file": {
      return (
        <FieldFile
          fieldDef={fieldDef}
          fieldApi={fieldApi}
          renderer={renderer}
          rendererOptions={rendererOptions}
        />
      );
    }

    case "relation": {
      return (
        <FieldRelation
          fieldDef={fieldDef as RelationFieldDefinition}
          fieldApi={fieldApi}
          renderer={renderer}
          rendererOptions={rendererOptions}
        />
      );
    }

    default: {
      return (
        <FieldInput
          fieldDef={{ ...fieldDef, type: "string" } as FieldDefinition}
          fieldApi={fieldApi}
          renderer={renderer}
          rendererOptions={rendererOptions}
        />
      );
    }
  }
};

export const ContentField = ({
  fieldName,
  renderer,
  rendererOptions,
}: ContentFieldProps) => {
  const form = useContentEditForm();
  const fieldDef = useFieldDefinition(fieldName);

  if (!fieldDef) {
    return null;
  }

  return (
    <form.Field
      name={fieldName}
      children={(fieldApi) => (
        <FieldRenderer
          fieldDef={fieldDef}
          fieldApi={fieldApi}
          renderer={renderer}
          rendererOptions={rendererOptions}
        />
      )}
    />
  );
};

