import type { BaseFieldProps } from "../types";
import type { FieldDefinition, FieldType } from "fastschema";

export type FieldRendererComponent = React.ComponentType<BaseFieldProps>;

/**
 * Options for registering a field renderer
 */
export interface RendererRegistrationOptions {
  /** Priority for default selection (higher = preferred) */
  priority?: number;
  /** Human-readable label for UI display */
  label?: string;
  /** Settings schema - rendered using FieldRenderer */
  settingsFields?: FieldDefinition[];
}

/**
 * Registry entry for a field renderer
 */
export interface RendererEntry {
  /** Renderer name (e.g., 'input', 'color_picker', 'switch') */
  renderer: string;
  /** React component for rendering the field */
  component: FieldRendererComponent;
  /** Priority for default selection (higher = preferred) */
  priority?: number;
  /** Human-readable label for UI display */
  label?: string;
  /** Settings schema - rendered using FieldRenderer */
  settingsFields?: FieldDefinition[];
}

/**
 * Field renderer registry - manages custom field renderers
 *
 * Usage:
 * ```ts
 * // Register a custom renderer
 * fieldRegistry.register('string', 'markdown', MarkdownEditor, { label: 'Markdown Editor' });
 *
 * // Get renderer for a field
 * const Renderer = fieldRegistry.getRenderer(fieldDef);
 * ```
 */
class FieldRendererRegistry {
  private renderers = new Map<string, RendererEntry[]>();

  /**
   * Register a renderer for a field type
   * @param fieldType - The field type (e.g., 'string', 'bool', 'time')
   * @param renderer - Unique name for this renderer
   * @param component - React component to render the field
   * @param options - Registration options (priority, label, settingsFields)
   */
  register(
    fieldType: string,
    renderer: string,
    component: FieldRendererComponent,
    options: RendererRegistrationOptions = {},
  ): void {
    const entries = this.renderers.get(fieldType) ?? [];

    // Remove existing entry with same renderer if exists
    const filtered = entries.filter((e) => e.renderer !== renderer);

    filtered.push({
      renderer,
      component,
      priority: options.priority,
      label: options.label,
      settingsFields: options.settingsFields,
    });

    // Sort by priority (highest first)
    filtered.sort((a, b) => (b.priority ?? 0) - (a.priority ?? 0));

    this.renderers.set(fieldType, filtered);
  }

  /**
   * Unregister a renderer
   */
  unregister(fieldType: string, renderer: string): void {
    const entries = this.renderers.get(fieldType);
    if (entries) {
      this.renderers.set(
        fieldType,
        entries.filter((e) => e.renderer !== renderer),
      );
    }
  }

  /**
   * Get the renderer component for a field
   * Looks for matching renderer (from zone or field), falls back to default
   * @param fieldDef - Field definition
   * @param renderer - Optional renderer name from zone settings (takes precedence)
   */
  getRenderer(
    fieldDef: FieldDefinition,
    renderer?: string,
  ): FieldRendererComponent | null {
    const entries = this.renderers.get(fieldDef.type);
    if (!entries?.length) {
      return null;
    }

    // Zone-level renderer takes precedence
    if (renderer) {
      const matched = entries.find((e) => e.renderer === renderer);
      if (matched) {
        return matched.component;
      }
    }

    // Return highest priority renderer as default
    return entries[0]?.component ?? null;
  }

  /**
   * Get all registered renderers for a field type
   */
  getRenderers(fieldType: FieldType): RendererEntry[] {
    return this.renderers.get(fieldType) ?? [];
  }

  /**
   * Get a specific renderer entry by fieldType and renderer
   */
  getEntry(fieldType: string, renderer?: string): RendererEntry | undefined {
    const entries = this.renderers.get(fieldType);
    if (!entries?.length || !renderer) {
      return undefined;
    }
    return entries.find((e) => e.renderer === renderer);
  }

  /**
   * Check if a renderer is registered
   */
  hasRenderer(fieldType: string, renderer?: string): boolean {
    const entries = this.renderers.get(fieldType);
    if (!entries?.length) {
      return false;
    }
    if (renderer) {
      return entries.some((e) => e.renderer === renderer);
    }
    return true;
  }

  /**
   * Clear all registrations (useful for testing)
   */
  clear(): void {
    this.renderers.clear();
  }
}

/**
 * Global field renderer registry instance
 *
 * Register custom renderers:
 * ```ts
 * import { fieldRegistry } from './fields-v2';
 *
 * fieldRegistry.register('string', 'my_custom', MyCustomRenderer);
 * ```
 */
export const fieldRegistry = new FieldRendererRegistry();

/**
 * Convenience function to register default renderers
 * Called during app initialization
 */
export function registerDefaultRenderers(
  renderers: Record<string, Record<string, FieldRendererComponent>>,
): void {
  for (const [fieldType, typeRenderers] of Object.entries(renderers)) {
    for (const [renderer, component] of Object.entries(typeRenderers)) {
      fieldRegistry.register(fieldType, renderer, component);
    }
  }
}

import * as z from "zod";

import type { FieldDefinition, SchemaDefinition } from "fastschema";

import { slugToTitle } from "@/components/fsui/fscommon";

/**
 * Create Zod schema for a string field
 */
function createStringSchema(fieldDef: FieldDefinition): z.ZodTypeAny {
  let schema = z.string();

  if (!fieldDef.optional) {
    schema = schema.trim().min(1, {
      message: `${slugToTitle(fieldDef.name)} is required`,
    }) as typeof schema;
  }

  const maxSize = fieldDef.size ?? 0;
  if (maxSize > 0) {
    schema = schema.max(maxSize, {
      message: `${slugToTitle(fieldDef.name)} must be at most ${maxSize} characters`,
    }) as typeof schema;
  }

  return schema;
}

/**
 * Create Zod schema for an integer field
 */
function createIntSchema(fieldDef: FieldDefinition): z.ZodTypeAny {
  const label = slugToTitle(fieldDef.name);

  let schema = z.coerce
    .number({
      message: `${label} must be an integer`,
    })
    .int({
      message: `${label} must be an integer`,
    });

  // Add constraints based on int type
  switch (fieldDef.type) {
    case "int8": {
      schema = schema.min(-128).max(127);
      break;
    }
    case "int16": {
      schema = schema.min(-32768).max(32767);
      break;
    }
    case "int32": {
      schema = schema.min(-2147483648).max(2147483647);
      break;
    }
    // int64 and int have no JS number constraints
  }

  return schema;
}

/**
 * Create Zod schema for an unsigned integer field
 */
function createUintSchema(fieldDef: FieldDefinition): z.ZodTypeAny {
  const label = slugToTitle(fieldDef.name);

  let schema = z
    .number({
      message: `${label} must be a positive integer`,
    })
    .nonnegative({
      message: `${label} must be a positive integer`,
    });

  // Add constraints based on uint type
  switch (fieldDef.type) {
    case "uint8": {
      schema = schema.max(255);
      break;
    }
    case "uint16": {
      schema = schema.max(65535);
      break;
    }
    case "uint32": {
      schema = schema.max(4294967295);
      break;
    }
    // uint64 and uint have no practical JS number constraints
  }

  return schema;
}

/**
 * Create Zod schema for a float field
 */
function createFloatSchema(fieldDef: FieldDefinition): z.ZodTypeAny {
  const label = slugToTitle(fieldDef.name);

  return z.coerce.number({
    message: `${label} must be a number`,
  });
}

/**
 * Create Zod schema for a boolean field
 */
function createBoolSchema(): z.ZodTypeAny {
  return z.boolean();
}

/**
 * Create Zod schema for a time field
 */
function createTimeSchema(): z.ZodTypeAny {
  return z.string();
}

/**
 * Create Zod schema for a JSON field
 */
function createJsonSchema(): z.ZodTypeAny {
  return z.any();
}

/**
 * Create Zod schema for an enum field
 */
function createEnumSchema(fieldDef: FieldDefinition): z.ZodTypeAny {
  const enumValues = fieldDef.enums?.map(({ value }) => value) ?? [];

  if (enumValues.length === 0) {
    return z.string();
  }

  const [first, ...rest] = enumValues;
  return z.enum([first, ...rest]);
}

/**
 * Relation value types for Zod validation
 */
const relationSingleZodObject = z
  .object({
    id: z.number().optional(),
  })
  .optional()
  .nullable();

const relationArrayZodObject = z
  .union([
    z.array(z.object({ id: z.number() })),
    z.object({
      $nochange: z.boolean().optional(),
      $add: z.array(z.any()).optional(),
      $clear: z.array(z.any()).optional(),
    }),
  ])
  .optional()
  .nullable();

/**
 * Create Zod schema for a relation field
 */
function createRelationSchema(fieldDef: FieldDefinition): z.ZodTypeAny {
  const isArray =
    fieldDef.multiple ||
    fieldDef.relation?.type === "m2m" ||
    (fieldDef.relation?.type === "o2m" && fieldDef.relation?.owner);

  return isArray ? relationArrayZodObject : relationSingleZodObject;
}

/**
 * Create Zod schema for a single field definition
 */
export function createFieldZodSchema(fieldDef: FieldDefinition): z.ZodTypeAny {
  let schema: z.ZodTypeAny;

  switch (fieldDef.type) {
    case "string":
    case "text":
    case "uuid":
    case "bytes": {
      schema = createStringSchema(fieldDef);
      break;
    }

    case "int":
    case "int8":
    case "int16":
    case "int32":
    case "int64": {
      schema = createIntSchema(fieldDef);
      break;
    }

    case "uint":
    case "uint8":
    case "uint16":
    case "uint32":
    case "uint64": {
      schema = createUintSchema(fieldDef);
      break;
    }

    case "float32":
    case "float64": {
      schema = createFloatSchema(fieldDef);
      break;
    }

    case "bool": {
      schema = createBoolSchema();
      break;
    }

    case "time": {
      schema = createTimeSchema();
      break;
    }

    case "json": {
      schema = createJsonSchema();
      break;
    }

    case "enum": {
      schema = createEnumSchema(fieldDef);
      break;
    }

    case "relation":
    case "file": {
      schema = createRelationSchema(fieldDef);
      break;
    }

    default: {
      schema = z.any();
    }
  }

  // Handle optional fields
  if (fieldDef.optional) {
    schema = schema.nullable().optional();
  }

  return schema;
}

/**
 * Create a Zod object schema for an entire schema definition
 */
export function createSchemaZodObject(
  schemaDefinition: SchemaDefinition,
): z.ZodObject<Record<string, z.ZodTypeAny>> {
  const shape: Record<string, z.ZodTypeAny> = {};

  for (const fieldDef of schemaDefinition.fields) {
    // Skip locked fields (system-managed)
    if (fieldDef.is_system_field) {
      continue;
    }

    shape[fieldDef.name] = createFieldZodSchema(fieldDef);
  }

  return z.object(shape);
}

/**
 * Get default value for a field based on its type and definition
 */
export function getFieldDefaultValue(
  fieldDef: FieldDefinition,
  existingValue?: unknown,
): unknown {
  // If we have an existing value, use it
  if (existingValue !== undefined) {
    return existingValue;
  }

  // Use field's default value if defined
  if (fieldDef.default !== undefined && fieldDef.default !== "") {
    switch (fieldDef.type) {
      case "int":
      case "int8":
      case "int16":
      case "int32":
      case "int64":
      case "uint":
      case "uint8":
      case "uint16":
      case "uint32":
      case "uint64": {
        return Number.parseInt(fieldDef.default, 10);
      }

      case "float32":
      case "float64": {
        return Number.parseFloat(fieldDef.default);
      }

      case "bool": {
        return fieldDef.default === "true";
      }

      case "json": {
        try {
          return JSON.parse(fieldDef.default);
        } catch {
          return "";
        }
      }

      case "time": {
        return new Date(fieldDef.default);
      }

      default: {
        return fieldDef.default;
      }
    }
  }

  // Type-specific defaults
  switch (fieldDef.type) {
    case "bool": {
      return false;
    }

    case "enum": {
      return fieldDef.enums?.[0]?.value ?? "";
    }

    case "relation":
    case "file": {
      const isArray =
        fieldDef.multiple ||
        fieldDef.relation?.type === "m2m" ||
        (fieldDef.relation?.type === "o2m" && fieldDef.relation?.owner);
      return isArray ? [] : fieldDef.optional ? null : undefined;
    }

    case "time": {
      return undefined;
    }

    default: {
      return "";
    }
  }
}

/**
 * Create default values object for a schema
 */
export function createSchemaDefaultValues(
  schemaDefinition: SchemaDefinition,
  existingContent?: Record<string, unknown>,
): Record<string, unknown> {
  const defaults: Record<string, unknown> = {};

  for (const fieldDef of schemaDefinition.fields) {
    if (fieldDef.is_system_field) {
      continue;
    }

    defaults[fieldDef.name] = getFieldDefaultValue(
      fieldDef,
      existingContent?.[fieldDef.name],
    );
  }

  return defaults;
}

import { LoaderIcon, SaveIcon } from "lucide-react";
import { Fragment } from "react";

import { Button } from "@/components/ui/button";

import { FormErrors } from "../fsform/error";

import { ContentEditContext } from "./context";
import { useCreateContentForm } from "./use-create-content-form";

import type { Entity, SchemaDefinition } from "fastschema";

export interface ContentFormProps {
  schemaDefinition: SchemaDefinition;
  initialData?: Entity;
  onSubmit?: (data: Entity) => Promise<void> | void;
  onSuccess?: (data: Entity) => void;
}

export const ContentForm = ({
  schemaDefinition: schemaDef,
  initialData,
  onSubmit,
  onSuccess,
}: ContentFormProps) => {
  const { form, formErrors, pkValue, label, view, zones, getField } =
    useCreateContentForm({
      schemaDef,
      initialData,
      withFiles: true,
      withRelations: true,
      onSubmit,
      onSuccess,
    });

  return (
    <Fragment>
      <ContentEditContext.Provider
        value={{
          form,
          schemaDef,
          pkValue,
          getField,
        }}
      >
        <form
          onSubmit={(e) => {
            e.preventDefault();
            form.handleSubmit();
          }}
        >
          <div className="flex items-center justify-between gap-2">
            <div className="flex flex-col gap-1 px-1">
              <h2 className="text-xl font-semibold tracking-tight">
                {initialData ? `Edit ${label}` : `Create ${label}`}
              </h2>
              <p className="text-muted-foreground">
                {initialData
                  ? `Update the ${label} record.`
                  : `Create a new ${label} record.`}
              </p>
            </div>
            <div className="flex items-center gap-2">
              <FormErrors errors={formErrors} />
              <form.Subscribe
                selector={(state) => [state.canSubmit, state.isSubmitting]}
                children={([canSubmit, isSubmitting]) => (
                  <Button
                    type="submit"
                    size="sm"
                    disabled={
                      !canSubmit || isSubmitting || formErrors.length > 0
                    }
                  >
                    {isSubmitting ? (
                      <Fragment>
                        <LoaderIcon className="animate-spin" />
                        <span>Saving...</span>
                      </Fragment>
                    ) : (
                      <Fragment>
                        <SaveIcon className="size-3.5" />
                        <span>{initialData ? "Update" : "Create"}</span>
                      </Fragment>
                    )}
                  </Button>
                )}
              />
            </div>
          </div>

          <div className="mt-5 px-1">{view.render({ zones })}</div>
        </form>
      </ContentEditContext.Provider>
    </Fragment>
  );
};

import type { FieldApiOnChangeType } from "../fsform/fsform";
import type { FieldDefinition } from "fastschema";
import type * as z from "zod";

export type RendererOptions = Record<string, unknown>;

export interface BaseFieldProps<
  FormDataSchema extends z.ZodObject = z.ZodObject,
> {
  fieldDef: FieldDefinition;
  fieldApi: FieldApiOnChangeType<FormDataSchema>;
  className?: string;
  /** Renderer name from zone settings */
  renderer?: string;
  /** Renderer options from zone settings */
  rendererOptions?: RendererOptions;
}

export interface ControlledFieldProps {
  fieldDef: FieldDefinition;
  value: unknown;
  onChange: (value: unknown) => void;
  onBlur?: () => void;
  /** Renderer name from zone settings */
  renderer?: string;
  /** Renderer options from zone settings */
  rendererOptions?: RendererOptions;
}

export type FieldProps<FormDataSchema extends z.ZodObject = z.ZodObject> =
  | BaseFieldProps<FormDataSchema>
  | ControlledFieldProps;

import { useForm, useStore } from "@tanstack/react-form";
import {
  createDefaultFormValues,
  createRootZodSchema,
  type PKType,
  type SchemaDefinition,
  type SchemaGeneratorOptions,
} from "fastschema";
import { useFastSchema } from "fastschema/react";
import { useCallback } from "react";
import { toast } from "sonner";

import {
  populateActiveFormViewSettings,
  schemaContentViews as contentViews,
  titleCase,
  type ViewType,
} from "@/components/fsui/fscommon";

import { createZones } from "./zone";

import type { UseFormReturnOnChangeType } from "../fsform/fsform";
import type z from "zod";

export interface UseCreateContentFormProps<T extends z.ZodObject = z.ZodObject>
  extends SchemaGeneratorOptions {
  schemaDef: SchemaDefinition;
  initialData?: z.infer<T>;
  dataOnly?: boolean;
  zodSchema?: T;
  onSubmit?: (data: z.infer<T>) => Promise<void> | void;
  onSuccess?: (data: z.infer<T>) => void;
}

export const useCreateContentForm = <T extends z.ZodObject = z.ZodObject>({
  schemaDef,
  initialData,
  dataOnly,
  zodSchema,
  onSubmit,
  onSuccess,
  ...generatorOptions
}: UseCreateContentFormProps<T>) => {
  const { fastschema } = useFastSchema();
  const pkValue = initialData?.[schemaDef.primary_field || "id"] as PKType;
  const isEditing = Boolean(pkValue);
  const withRelations = !isEditing;
  const fieldMap = new Map(schemaDef.fields.map((f) => [f.name, f]));
  const label = titleCase(schemaDef.name);
  const _zodSchema =
    zodSchema ||
    createRootZodSchema(schemaDef, {
      withRelations,
      ...generatorOptions,
    });
  const defaultValues = createDefaultFormValues<typeof _zodSchema>(
    schemaDef,
    initialData,
    {
      withRelations,
      ...generatorOptions,
    },
  );

  const { view, zones } = dataOnly
    ? { view: contentViews[0] as ViewType, zones: {} }
    : (() => {
        const settings = schemaDef.settings?.form || {};
        const activeView = settings.active_view || contentViews[0].id;
        const savedView = settings.views?.[activeView];
        const _view: ViewType =
          contentViews.find((v) => v.id === activeView) || contentViews[0];
        return {
          view: _view,
          zones: createZones(
            schemaDef,
            Object.keys(savedView || {}).length > 0
              ? savedView
              : populateActiveFormViewSettings(schemaDef).zones,
            _view,
          ),
        };
      })();

  const handleSubmit = useCallback(
    async (data: z.infer<T>) => {
      if (onSubmit) {
        await onSubmit(data);
        return;
      }

      try {
        const result = await fastschema.saveSchemaContent(schemaDef, data);
        onSuccess?.(result as z.infer<T>);
        toast.success(`${label} saved successfully`);
      } catch (error) {
        toast.error(`Failed to save ${label}: ${(error as Error).message}`);
        throw error;
      }
    },
    [fastschema, schemaDef, label, onSubmit, onSuccess],
  );

  const form = useForm({
    defaultValues,
    validators: { onChange: _zodSchema },
    onSubmit: ({ value }) => handleSubmit(value as z.infer<T>),
  }) as unknown as UseFormReturnOnChangeType<T>;

  return {
    form,
    formErrors: useStore(form.store, (state) => state.errors),
    pkValue,
    label,
    view,
    zones,
    getField: (name: string) => fieldMap.get(name),
  };
};

import { FieldGroup } from "@/components/ui/field";

import { useSchemaDefinition } from "./context";
import { ContentField } from "./fields-v2";

import type { SchemaViewType } from "../fscommon";
import type { SchemaDefinition, ZoneFieldSettings } from "fastschema";
import type { ReactNode } from "react";

export interface ZoneRendererProps {
  zoneId?: string;
  zoneItems: ZoneFieldSettings[];
}

/**
 * ZoneRenderer - Renders all fields in a layout zone
 */
export const ZoneRenderer = ({ zoneId, zoneItems }: ZoneRendererProps) => {
  const schemaDefinition = useSchemaDefinition();
  const hiddenFields = schemaDefinition.settings?.form?.hidden_fields ?? [];
  const visibleItems = zoneItems.filter(
    (item) => !hiddenFields.includes(item.field),
  );

  if (visibleItems.length === 0) {
    return (
      <div className="bg-muted/50 flex min-h-[100px] items-center justify-center rounded-lg border border-dashed p-6">
        <p className="text-muted-foreground text-sm">No fields in this zone</p>
      </div>
    );
  }

  return (
    <div
      data-zone={zoneId}
      className="flex flex-col gap-4"
    >
      <FieldGroup>
        {visibleItems.map((item) => (
          <ContentField
            key={item.field}
            fieldName={item.field}
            renderer={item.renderer}
            rendererOptions={item.options}
          />
        ))}
      </FieldGroup>
    </div>
  );
};

export const getZoneItems = (
  schemaDef: SchemaDefinition,
  viewConfig: Record<string, ZoneFieldSettings[]>,
  zoneId: string,
): ZoneFieldSettings[] => {
  // If zone config exists, use it
  if (viewConfig[zoneId]) {
    return viewConfig[zoneId].filter((item) => {
      const field = schemaDef.fields.find((f) => f.name === item.field);
      return field?.immutable !== true;
    });
  }

  // Auto-distribute: main zone gets all non-system fields
  if (zoneId === "main") {
    return schemaDef.fields
      .filter((f) => !f.immutable)
      .map((f) => ({ field: f.name }));
  }

  return [];
};

export const createZones = (
  schemaDef: SchemaDefinition,
  viewConfig: Record<string, ZoneFieldSettings[]>,
  view: SchemaViewType<Record<string, string>>,
) => {
  {
    const result = {} as Record<string, ReactNode>;
    for (const zoneId in view.zones) {
      if (Object.prototype.hasOwnProperty.call(view.zones, zoneId)) {
        const zoneItems = getZoneItems(schemaDef, viewConfig, zoneId);
        result[zoneId] = (
          <div
            key={zoneId}
            className="w-full rounded-lg border border-t-5 p-6"
          >
            <ZoneRenderer zoneItems={zoneItems} />
          </div>
        );
      }
    }

    return result;
  }
};
